  ('optician-moex-00787', 'optician', 'optician-moex-111-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '視網膜檢影鏡的光束（lightstreak）與100度的方向平行時，反射光（lightreflex）被-1.25D鏡片中和，而 光束與10度的方向平行時，反射光（lightreflex）被+0.50D鏡片中和。檢查者的工作距離為57cm。此受 測者有那種類型的散光？', '["混合性散光（mixedastigmatism）", "單純性遠視散光（simplehyperopicastigmatism）", "複合性近視散光（compoundmyopicastigmatism）", "複合性遠視散光（compoundhyperopicastigmatism）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "898af7d6caca", "answer_pdf_sha1": "1ed372d5a357", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1007", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
